  "(included)": { fr: "(inclus)", es: "(incluido)", pt: "(incluído)", ar: "(مُضمَّن)", de: "(inbegriffen)", it: "(incluso)", zh: "(已包含)", hi: "(शामिल)", ig: "(tinyere)", yo: "(ó wà nínú rẹ̀)", ha: "(an haɗa)" },
  "About HenryCo Care": { fr: "À propos de HenryCo Care", es: "Acerca de HenryCo Care", pt: "Sobre o HenryCo Care", ar: "نبذة عن HenryCo Care", de: "Über HenryCo Care", it: "Informazioni su HenryCo Care", zh: "关于 HenryCo Care", hi: "HenryCo Care के बारे में", ig: "Maka HenryCo Care", yo: "Nípa HenryCo Care", ha: "Game da HenryCo Care" },
  "Access instructions, parking guidance, focus areas, entry notes, supervisor details, or support context.": { fr: "Instructions d'accès, conseils de stationnement, zones prioritaires, notes d'entrée, coordonnées du superviseur ou contexte de soutien.", es: "Instrucciones de acceso, guía de estacionamiento, áreas prioritarias, notas de entrada, detalles del supervisor o contexto de apoyo.", pt: "Instruções de acesso, orientação de estacionamento, áreas prioritárias, notas de entrada, detalhes do supervisor ou contexto de apoio.", ar: "تعليمات الدخول، إرشادات الوقوف، مناطق التركيز، ملاحظات الدخول، تفاصيل المشرف، أو سياق الدعم.", de: "Zugangshinweise, Parkanleitung, Schwerpunktbereiche, Eingangshinweise, Aufseherdaten oder Support-Kontext.", it: "Istruzioni di accesso, indicazioni per il parcheggio, aree prioritarie, note di ingresso, dettagli del supervisore o contesto di supporto.", zh: "访问说明、停车指引、重点区域、入口备注、主管详情或支持背景信息。", hi: "प्रवेश निर्देश, पार्किंग मार्गदर्शन, फोकस क्षेत्र, प्रवेश नोट्स, पर्यवेक्षक विवरण, या सहायता संदर्भ।", ig: "Ntụziaka ịbanye, nduzi ebe ndọba ụgbọala, ebe nlebara anya, ndetu mbata, nkọwa onye nlekọta, ma ọ bụ ọnọdụ nkwado.", yo: "Àwọn ìtọ́sọ́nà ìwọlé, ìtọ́sọ́nà ìpàrọ́ ọkọ̀, agbègbè àfojúsùn, àkọsílẹ̀ ìwọlé, alàyé alábòójútó, tàbí àyíká àtìlẹ́yìn.", ha: "Umarnin shiga, jagorar wurin ajiye motoci, wuraren da aka mai da hankali, bayanan shiga, bayanan mai kulawa, ko mahallin tallafi." },
  "Access note": { fr: "Note d'accès", es: "Nota de acceso", pt: "Nota de acesso", ar: "ملاحظة الدخول", de: "Zugangshinweis", it: "Nota di accesso", zh: "访问备注", hi: "प्रवेश नोट", ig: "Ndetu ịbanye", yo: "Àkọsílẹ̀ ìwọlé", ha: "Bayanin shiga" },
  "Access state": { fr: "État d'accès", es: "Estado de acceso", pt: "Estado de acesso", ar: "حالة الدخول", de: "Zugangsstatus", it: "Stato di accesso", zh: "访问状态", hi: "प्रवेश स्थिति", ig: "Ọnọdụ ịbanye", yo: "Ipò ìwọlé", ha: "Matsayin shiga" },
