  "Active bookings": { fr: "Réservations actives", es: "Reservas activas", pt: "Reservas ativas", ar: "الحجوزات النشطة", de: "Aktive Buchungen", it: "Prenotazioni attive", zh: "有效预订", hi: "सक्रिय बुकिंग", ig: "Ndoputa na-arụ ọrụ", yo: "Àwọn ìwé ìfipámọ́ ńṣiṣẹ́", ha: "Rajistar aiki masu aiki" },
  "Active immediately": { fr: "Actif immédiatement", es: "Activo de inmediato", pt: "Ativo imediatamente", ar: "نشط على الفور", de: "Sofort aktiv", it: "Attivo immediatamente", zh: "立即生效", hi: "तुरंत सक्रिय", ig: "Na-arụ ọrụ ozugbo", yo: "Ńṣiṣẹ́ lẹ́sẹ̀kẹsẹ̀", ha: "Yana aiki nan take" },
