  "Bedrooms to prepare": { fr: "Chambres à préparer", es: "Habitaciones a preparar", pt: "Quartos para preparar", ar: "غرف النوم المراد إعدادها", de: "Vorzubereitende Schlafzimmer", it: "Camere da letto da preparare", zh: "需准备的卧室", hi: "तैयार करने हेतु बेडरूम", ig: "Ime ụlọ ehi ụra a ga-akwado", yo: "Yàrá ìbùsùn tí a fẹ́ múrasílẹ̀", ha: "Ɗakunan kwana da za a shirya" },
  "Blocked from normal use": { fr: "Bloqué pour usage normal", es: "Bloqueado para uso normal", pt: "Bloqueado do uso normal", ar: "محظور من الاستخدام العادي", de: "Von normaler Nutzung gesperrt", it: "Bloccato dall'uso normale", zh: "已禁止正常使用", hi: "सामान्य उपयोग से अवरुद्ध", ig: "Egbochiri site na ojiji nkịtị", yo: "Tí a dí lọ́wọ́ lílò bí ó ti yẹ", ha: "An toshe daga amfani na yau da kullun" },
  "Blue gate house, flat 4B, or family home": { fr: "Maison à portail bleu, appartement 4B, ou maison familiale", es: "Casa de portón azul, piso 4B, o casa familiar", pt: "Casa de portão azul, apartamento 4B, ou casa de família", ar: "منزل البوابة الزرقاء، الشقة 4B، أو منزل عائلي", de: "Haus mit blauem Tor, Wohnung 4B, oder Familienhaus", it: "Casa con cancello blu, appartamento 4B, o casa di famiglia", zh: "蓝色大门的房子、4B 公寓,或家庭住宅", hi: "नीले गेट वाला घर, फ्लैट 4B, या पारिवारिक घर", ig: "Ụlọ ọnụ ụzọ ámá na-acha anụnụ anụnụ, flat 4B, ma ọ bụ ụlọ ezinaụlọ", yo: "Ilé ẹnu-ọ̀nà aláwọ̀ búlúù, flat 4B, tàbí ilé ìdílé", ha: "Gidan ƙofar shuɗi, ɗaki 4B, ko gidan iyali" },
  "Book Service": { fr: "Réserver le service", es: "Reservar servicio", pt: "Reservar serviço", ar: "احجز الخدمة", de: "Service buchen", it: "Prenota servizio", zh: "预订服务", hi: "सेवा बुक करें", ig: "Doputa ọrụ", yo: "Wé iṣẹ́ pamọ́", ha: "Yi rajistar sabis" },
  "Book a service": { fr: "Réserver un service", es: "Reservar un servicio", pt: "Reservar um serviço", ar: "احجز خدمة", de: "Einen Service buchen", it: "Prenota un servizio", zh: "预订一项服务", hi: "एक सेवा बुक करें", ig: "Doputa otu ọrụ", yo: "Wé iṣẹ́ kan pamọ́", ha: "Yi rajistar sabis ɗaya" },
  "Book a service. One calm form.": { fr: "Réservez un service. Un formulaire serein.", es: "Reserva un servicio. Un formulario tranquilo.", pt: "Reserve um serviço. Um formulário tranquilo.", ar: "احجز خدمة. نموذج واحد هادئ.", de: "Buchen Sie einen Service. Ein ruhiges Formular.", it: "Prenota un servizio. Un modulo sereno.", zh: "预订服务。一份简洁的表格。", hi: "एक सेवा बुक करें। एक शांत फ़ॉर्म।", ig: "Debe ọrụ. Otu fọm dị jụụ.", yo: "Ṣe ìwé-ìfilọ́lẹ̀ iṣẹ́. Fọ́ọ̀mù kan tó rọrùn.", ha: "Yi rajistar sabis. Fom guda mai sauƙi." },
  "Book garment pickup and return delivery, recurring home cleaning, or office cleaning through one calmer service flow with clear timing, payment follow-up, and live updates.": { fr: "Réservez la collecte et la livraison de vêtements, le nettoyage récurrent à domicile ou le nettoyage de bureaux via un flux de service plus serein avec des horaires clairs, un suivi de paiement et des mises à jour en direct.", es: "Reserva recogida y entrega de prendas, limpieza recurrente del hogar o limpieza de oficinas mediante un flujo de servicio más tranquilo con horarios claros, seguimiento de pagos y actualizaciones en vivo.", pt: "Agende a recolha e entrega de vestuário, limpeza doméstica recorrente ou limpeza de escritórios através de um fluxo de serviço mais tranquilo com horários claros, acompanhamento de pagamento e atualizações ao vivo.", ar: "احجز استلام الملابس وتسليمها، أو التنظيف المنزلي المتكرر، أو تنظيف المكاتب من خلال تدفق خدمة أكثر هدوءاً مع توقيت واضح ومتابعة الدفع وتحديثات مباشرة.", de: "Buchen Sie Kleidungsabholung und Rücklieferung, wiederkehrende Hausreinigung oder Büroreinigung über einen ruhigeren Service-Ablauf mit klarer Zeitplanung, Zahlungsverfolgung und Live-Updates.", it: "Prenota ritiro e consegna di indumenti, pulizie domestiche ricorrenti o pulizie d'ufficio con un flusso di servizio più sereno, orari chiari, monitoraggio dei pagamenti e aggiornamenti in tempo reale.", zh: "通过更顺畅的服务流程,预订衣物上门取送、定期家庭清洁或办公室清洁,享受清晰时间安排、付款跟进和实时更新。", hi: "स्पष्ट समय, भुगतान फ़ॉलो-अप और लाइव अपडेट के साथ एक शांत सेवा प्रवाह के माध्यम से कपड़ों की पिकअप और रिटर्न डिलीवरी, नियमित घरेलू सफाई या कार्यालय सफाई बुक करें।", ig: "Debe nbulata akwa na nnyefe nloghachi, nhicha ụlọ na-emegharị emegharị, ma ọ bụ nhicha ụlọ ọrụ site n'otu usoro ọrụ dị jụụ nke nwere oge doro anya, nsochi ịkwụ ụgwọ, na mmelite ndụ.", yo: "Ṣe ìwé-ìfilọ́lẹ̀ fún gbígbé aṣọ jáde àti ìfijíṣẹ́ ìpadàwálé, ìwẹ̀nù ilé tó ń tún ṣẹlẹ̀, tàbí ìwẹ̀nù ọ́fíìsì nípasẹ̀ ìṣàn-iṣẹ́ tó rọrùn pẹ̀lú àkókò tó mọ́, ìtẹ̀lé ìsanwó, àti àwọn ìmúdójúìwọ̀n tààrà.", ha: "Yi rajistar ɗaukar tufafi da kawo su, tsaftace gida akai-akai, ko tsaftace ofis ta hanyar gudanar da hidima mai sauƙi tare da bayyananniyar lokaci, biyan kuɗi, da sabuntawa kai tsaye." },
  "Booking": { fr: "Réservation", es: "Reserva", pt: "Reserva", ar: "الحجز", de: "Buchung", it: "Prenotazione", zh: "预订", hi: "बुकिंग", ig: "Ndebe", yo: "Ìwé-ìfilọ́lẹ̀", ha: "Rajista" },
