  "Cancel": { fr: "Annuler", es: "Cancelar", pt: "Cancelar", ar: "إلغاء", de: "Abbrechen", it: "Annulla", zh: "取消", hi: "रद्द करें", ig: "Kagbuo", yo: "Fagilé", ha: "Soke" },
