  "Force sign-in again": { fr: "Forcer une nouvelle connexion", es: "Forzar inicio de sesión nuevamente", pt: "Forçar novo login", ar: "فرض تسجيل الدخول مرة أخرى", de: "Erneute Anmeldung erzwingen", it: "Forza nuovo accesso", zh: "强制重新登录", hi: "पुनः साइन-इन के लिए बाध्य करें", ig: "Manye ịbanye ọzọ", yo: "Fi agbára mú àtúnwọlé", ha: "Tilasta sake shiga" },
  "Forced re-login": { fr: "Reconnexion forcée", es: "Inicio de sesión forzado", pt: "Novo login forçado", ar: "إعادة تسجيل دخول إجبارية", de: "Erzwungene erneute Anmeldung", it: "Riaccesso forzato", zh: "强制重新登录", hi: "बाध्य पुनः लॉगिन", ig: "Mmanye nlọghachi banye", yo: "Àtúnwọlé tí a fi agbára mú", ha: "Sake shiga tilas" },
