  "Property or office label": { fr: "Étiquette de propriété ou de bureau", es: "Etiqueta de propiedad u oficina", pt: "Rótulo de propriedade ou escritório", ar: "تسمية العقار أو المكتب", de: "Bezeichnung der Immobilie oder des Büros", it: "Etichetta della proprietà o dell'ufficio", zh: "房产或办公室标签", hi: "संपत्ति या कार्यालय लेबल", ig: "Akara ụlọ ma ọ bụ ọfịs", yo: "Àmì ìdánimọ̀ ohun-ìní tàbí ọ́físì", ha: "Lakabin kadara ko ofis" },
  "Property type": { fr: "Type de propriété", es: "Tipo de propiedad", pt: "Tipo de propriedade", ar: "نوع العقار", de: "Immobilientyp", it: "Tipo di immobile", zh: "房产类型", hi: "संपत्ति का प्रकार", ig: "Ụdị ụlọ", yo: "Irú ohun-ìní", ha: "Nau'in kadara" },
  "Property, residence, or site address": { fr: "Adresse de la propriété, de la résidence ou du site", es: "Dirección de la propiedad, residencia o sitio", pt: "Endereço da propriedade, residência ou local", ar: "عنوان العقار أو المسكن أو الموقع", de: "Adresse der Immobilie, des Wohnsitzes oder des Standorts", it: "Indirizzo dell'immobile, residenza o sito", zh: "房产、住所或场地地址", hi: "संपत्ति, निवास या स्थल का पता", ig: "Adreesị ụlọ, ebe obibi, ma ọ bụ saịtị", yo: "Àdírẹ́sì ohun-ìní, ibùgbé, tàbí ojúlé", ha: "Adireshin kadara, mazauni, ko wuri" },
  "Protected actions and dashboard access may be logged for accountability.": { fr: "Les actions protégées et l'accès au tableau de bord peuvent être enregistrés à des fins de responsabilité.", es: "Las acciones protegidas y el acceso al panel pueden registrarse para fines de responsabilidad.", pt: "As ações protegidas e o acesso ao painel podem ser registrados para fins de responsabilização.", ar: "قد يتم تسجيل الإجراءات المحمية والوصول إلى لوحة التحكم لأغراض المساءلة.", de: "Geschützte Aktionen und der Zugriff auf das Dashboard können zur Rechenschaftspflicht protokolliert werden.", it: "Le azioni protette e l'accesso al dashboard possono essere registrati per la responsabilità.", zh: "受保护的操作和仪表板访问可能会被记录以供问责。", hi: "जवाबदेही के लिए संरक्षित कार्रवाइयाँ और डैशबोर्ड एक्सेस लॉग किए जा सकते हैं।", ig: "Enwere ike idekọ omume echekwara na nnweta dashboard maka ịza ajụjụ.", yo: "A lè ṣe àkọsílẹ̀ àwọn ìṣe tí a dáàbò bò àti àyè dashboard fún ìdíwọ́n.", ha: "Ana iya yin rajistar ayyukan da aka karewa da shiga dashboard don alhakin lissafi." },
