// ---- shared inject pipeline ----
const LOCS = ["fr", "es", "pt", "ar", "de", "it", "zh", "hi", "ig", "yo", "ha"];
const dictFile = path.join(process.cwd(), "packages", "i18n", "src", "surface-extra-labels.ts");
let src = fs.readFileSync(dictFile, "utf8");

function findDictBounds(s, locUpper) {
  const startRe = new RegExp(`export const EXTRA_SURFACE_LABELS_${locUpper}\\s*=\\s*\\{`);
  const m = startRe.exec(s);
  if (!m) return null;
  const blockStart = m.index + m[0].length;
  let depth = 1;
  let i = blockStart;
  while (i < s.length && depth > 0) {
    const ch = s[i];
    if (ch === "{") depth++;
    else if (ch === "}") depth--;
    else if (ch === '"' || ch === "'" || ch === "`") {
      const q = ch;
      i++;
      while (i < s.length && s[i] !== q) { if (s[i] === "\\") i++; i++; }
    }
    i++;
  }
  return { blockStart, blockEnd: i - 1 };
}

function escapeJSON(str) { return JSON.stringify(str); }

function collectExistingKeys(s, locUpper) {
  const b = findDictBounds(s, locUpper);
  if (!b) return new Set();
  const block = s.slice(b.blockStart, b.blockEnd);
  const keys = new Set();
  const RE_QUOTED = /(^|[\n,{])\s*(["'`])((?:\\.|(?!\2).)*)\2\s*:/g;
  let m;
  while ((m = RE_QUOTED.exec(block))) {
    let k = m[3];
    if (m[2] === '"' || m[2] === "'") {
      k = k.replace(/\\\\/g, "\\").replace(new RegExp(`\\\\${m[2]}`, "g"), m[2]).replace(/\\n/g, "\n").replace(/\\t/g, "\t");
    }
    keys.add(k);
  }
  const RE_BARE = /(^|[\n,{])\s*([A-Za-z_$][A-Za-z0-9_$]*)\s*:/g;
  while ((m = RE_BARE.exec(block))) keys.add(m[2]);
  return keys;
}

function entryLine(k, v) { return `  ${escapeJSON(k)}: ${escapeJSON(v)},`; }

function injectIntoDict(s, locUpper, additions) {
  const b = findDictBounds(s, locUpper);
  if (!b) return s;
  let j = b.blockEnd - 1;
  while (j > 0 && /\s/.test(s[j])) j--;
  let prefix = "";
  if (s[j] !== ",") prefix = s.slice(0, j + 1) + "," + s.slice(j + 1, b.blockEnd);
  else prefix = s.slice(0, b.blockEnd);
  const lines = additions.map(([k, v]) => entryLine(k, v));
  return prefix + "\n" + lines.join("\n") + "\n" + s.slice(b.blockEnd);
}

for (const loc of LOCS) {
  const locUpper = loc.toUpperCase();
  const existing = collectExistingKeys(src, locUpper);
  const additions = [];
  for (const [en, locales] of Object.entries(T)) {
    const tx = locales[loc];
    if (!tx) continue;
    if (existing.has(en)) continue;
    additions.push([en, tx]);
  }
  if (additions.length > 0) {
    console.log(`${locUpper}: adding ${additions.length} entries`);
    src = injectIntoDict(src, locUpper, additions);
  } else {
    console.log(`${locUpper}: nothing new to add`);
  }
}

fs.writeFileSync(dictFile, src);
console.log("Done. Care source strings:", Object.keys(T).length);
